SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for game_app_infos
-- ----------------------------
DROP TABLE IF EXISTS `game_app_infos`;
CREATE TABLE `game_app_infos`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `created_at` datetime(3) NULL DEFAULT NULL,
  `updated_at` datetime(3) NULL DEFAULT NULL,
  `deleted_at` datetime(3) NULL DEFAULT NULL,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '应用名称',
  `version` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '应用版本',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '应用下载地址',
  `status` bigint NOT NULL DEFAULT 1 COMMENT '状态:0-禁用,1-正常',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_game_app_infos_deleted_at`(`deleted_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of game_app_infos
-- ----------------------------
INSERT INTO `game_app_infos` VALUES (1, NULL, NULL, NULL, 'CYPoker', '1.0.0', 'http://192.168.1.1/cypoker_v1.0.0.pak', 1);

-- ----------------------------
-- Table structure for game_hand_histories
-- ----------------------------
DROP TABLE IF EXISTS `game_hand_histories`;
CREATE TABLE `game_hand_histories`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `room_number` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `hand_no` bigint NOT NULL,
  `kind` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `pot_total` decimal(18, 2) NOT NULL DEFAULT 0.00,
  `rake` decimal(18, 2) NOT NULL DEFAULT 0.00,
  `payouts_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `participants` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `settled_at` bigint NOT NULL,
  `detail_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_room_hand`(`room_number` ASC, `hand_no` ASC) USING BTREE,
  INDEX `idx_settled_at`(`settled_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 44 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

