-- ----------------------------
-- Table structure for game_users
-- ----------------------------
DROP TABLE IF EXISTS `game_users`;
CREATE TABLE `game_users`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `created_at` datetime(3) NULL DEFAULT NULL,
  `updated_at` datetime(3) NULL DEFAULT NULL,
  `deleted_at` datetime(3) NULL DEFAULT NULL,
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '用户ID',
  `device_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '设备ID',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '昵称',
  `avatar_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '头像URL',
  `level` bigint NOT NULL DEFAULT 0 COMMENT '等级',
  `experience` bigint NOT NULL DEFAULT 0 COMMENT '经验',
  `next_level_experience` bigint NOT NULL DEFAULT 1000 COMMENT '下一级所需经验',
  `wallet` double NOT NULL DEFAULT 0 COMMENT '钱包',
  `status` bigint NOT NULL DEFAULT 1 COMMENT '状态:0-禁用,1-正常',
  `last_login_at` datetime NULL DEFAULT NULL COMMENT '最后登录时间',
  `last_login_ip` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '最后登录IP',
  `login_count` bigint NOT NULL DEFAULT 0 COMMENT '登录次数',
  `is_vip` bigint NOT NULL DEFAULT 0 COMMENT '是否特权用户:0-否,1-是',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  UNIQUE INDEX `idx_device_id`(`device_id` ASC) USING BTREE,
  INDEX `idx_game_users_deleted_at`(`deleted_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2061269265683582977 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

